var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"기관 놈들……! 기어코 반격하려는 건가!","JPN":"機関のやつら……！　どうしても反撃するつもりか！","ENG":"Those Institution bastards...! Trying to fight back, huh?!","TWN":"機關的那些傢伙……！最終還是選擇反擊嗎？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그림자들을 지원하라! 파편을 빼앗길 수는 없다!","JPN":"シャドウを支援しろ！　破片を奪われるわけにはいかない！","ENG":"Support the Shadows! Don't let them take away the Fragment!","TWN":"支援暗影們！不能讓他們搶走碎片！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"크억……!","JPN":"くあっ……！","ENG":"Kuh...!","TWN":"咳呃……！"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"베네딕트를 찾으라고 보냈더니, 번거로운 일감을 떠맡고 왔군요.","JPN":"ベネディクトを探せと向かわせたのに、厄介な仕事を抱えて帰ってきましたね。","ENG":"I sent you to find Benedict, and you returned with a tedious assignment.","TWN":"派你去找本尼迪克特，結果你卻惹回來一堆麻煩事。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"뭐래, 안경 꼰대. 자기가 만나 보라고 해 놓고서.","JPN":"何言ってんだよ、眼鏡ばばあ。自分で会ってみろって言ったくせに。","ENG":"What are you saying, Specky Snob. You're the one who told me to go see him.","TWN":"你說什麼呢，眼鏡女。明明是你讓我去見他的。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저 분들…… 시신에서 뭔가 기어나오고 있어요.","JPN":"あの方々……死体から何かが這い出てきますわ。","ENG":"Those people... Something is crawling out from their corpses.","TWN":"那些人……屍體上有東西爬出來。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"맙소사. 넬슨이 만든 오징어 먹물 스파게티랑 빼닮았는데.","JPN":"うわぁ。ネルソンが作ったイカ墨パスタとそっくり。","ENG":"Oof. It looks just like Nelson's squid ink spaghetti!","TWN":"天啊，和尼爾森製作的魷魚墨汁義大利麵一樣。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"대체 저것들에게 뭘 먹인 거야? 거짓말하면 엉덩이 맴매해 준다?","JPN":"あれにいったい何を食べさせたんだ？　ウソついたら、お尻ぺんぺん食らわすよ。","ENG":"What in the world did they feed those things? I'm gonna spank you if you lie to me!","TWN":"到底餵那些東西吃了什麼？說謊的話會打屁股喔？"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그런 적 없어요, 자매님! 제가 만든 건 좀 더 상냥하다고요!","JPN":"食べさせたことなんかありません、シスター・シンディー！　私が作ったものはもっと優しいのです！","ENG":"That's not true, Sister! The ones I made were friendlier!","TWN":"我沒有，姐妹！我做的更溫柔一些！"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"……후우. 이 기회에 정보 기관에게 빚을 지워 둬서 나쁠 건 없죠.","JPN":"……ふう。この際、情報機関に貸しを作っておくのもいいでしょう。","ENG":"*Sigh...* I see no problem with using this opportunity to settle our debts with the intelligence agency.","TWN":"……呼，趁這個機會，還情報部門一個人情也不錯。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"적어도 저들이 철퇴 용병단의 실종 사건 당시 배후에 있던 건 읽어냈습니다.","JPN":"少なくとも彼らが鉄槌傭兵団の失踪事件当時、背後にいたということは読みました。","ENG":"At least, I read that they were responsible for the disappearance of the Mace Mercenary.","TWN":"至少他們在鐵鎚傭兵團失蹤案件當時，查出了幕後兇手。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"방패 용병단, 교전에 협조적으로 응해 주세요.","JPN":"盾傭兵団、交戦に協力してください。","ENG":"Shield Mercenary, please cooperate in combat.","TWN":"盾牌傭兵團，請配合一下交戰。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"저 소란은 뭐야? 설마 지원이 도착한 건가?","JPN":"あの騒動は何？　まさか支援が来たのかしら？","ENG":"What's all this commotion? Did their reinforcements arrive?","TWN":"那邊的騷亂是怎麼回事？難道是援軍到了？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"한눈 팔 틈이 있으려나, 최고 단원 씨.","JPN":"よそ見なんてしてる暇があるの？　首席奏者さん。","ENG":"I don't think you have time to worry about that, Ms. Elite Member.","TWN":"你還有閒工夫分心嗎，首席團員。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님, 퇴각해야겠어요. 이대로는 오히려 저희가 고사하게 생겼는걸요.","JPN":"マエストロ、退却しましょう。このままでは、むしろ私たちが枯死してしまいますわ。","ENG":"Chief Conductor, we must retreat. We'll be the ones to die at this rate!","TWN":"指揮家，該撤退了。照這樣下去，對我們反而不利。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};